# ======================================================================================================================\n# LAKEHOUSE MEDALLION ARCHITECTURE: BRONZE TO SILVER TRANSFORMATION\n# ======================================================================================================================\n# Purpose: This script implements a complete ETL pipeline following the medallion architecture pattern.\n#          It reads raw data from the Bronze layer, applies data quality rules and enrichment,\n#          and incrementally loads the cleaned data into the Silver layer using Delta Lake.\n#\n# Architecture Layers:\n#   - Bronze: Raw, unstructured data as-is from source systems\n#   - Silver: Cleaned, enriched, deduplicated data with business rules applied\n#   - Gold: Business-ready, aggregated data for analytics and reporting\n# ======================================================================================================================\n\n\n#1. Schema Definition & Ingestion (Bronze Layer)\n#This stage defines the expected structure of the raw CSV files to ensure data integrity during the read process.\n\nfrom pyspark.sql.types import *\n\n# Define the structure (Schema) for the sales data\n# This schema enforces strict data types during the CSV read operation\n# Benefits:\n#   - Converts string data to proper types (Date, Float, Integer)\n#   - Rejects malformed data that doesn't match the schema\n#   - Improves performance by avoiding type inference\norderSchema = StructType([(\n    StructField("SalesOrderNumber", StringType()),      # Unique order identifier\n    StructField("SalesOrderLineNumber", IntegerType()), # Line item number within the order\n    StructField("OrderDate", DateType()),               # Date the order was placed\n    StructField("CustomerName", StringType()),          # Name of the customer\n    StructField("Email", StringType()),                 # Customer email address\n    StructField("Item", StringType()),                  # Product/item name\n    StructField("Quantity", IntegerType()),             # Number of units ordered\n    StructField("UnitPrice", FloatType()),              # Price per unit\n    StructField("Tax", FloatType())                     # Tax amount for the order\n])\n\n# Read all CSV files from the 'bronze' folder\n# Pattern explanation: "Files/bronze/*.csv" = reads all CSV files in the bronze directory\n# .schema(orderSchema) = enforces the defined schema, converting data types automatically\n# This ensures consistent data format regardless of how the CSV was formatted\ndf = spark.read.format("csv") \n    .option("header", "true") \n    .schema(orderSchema) \n    .load("Files/bronze/*.csv")\n\ndisplay(df)\n#======================================================================================================================\n#======================================================================================================================\n\n\n#2. Cleaning & Enrichment (Silver Transformation)\n#In this step, we add technical metadata for auditing and handle missing values to "sanitize" the data.\n\nfrom pyspark.sql.functions import when, lit, col, current_timestamp, input_file_name\n\n# Add technical metadata columns for auditing purposes\n# These columns track data lineage and support compliance/debugging requirements\ndf = df.withColumn(\n    "FileName", \n    input_file_name()  # Captures the source file path (e.g., "Files/bronze/sales_2024.csv")\n                       # Useful for identifying data lineage and troubleshooting source issues\n) \n    .withColumn(\n    "IsFlagged", \n    # Business Rule: Flag orders older than August 1, 2019 for special handling\n    # This could indicate legacy data, special pricing, or data quality concerns\n    when(col("OrderDate") < '2019-08-01', True).otherwise(False)\n) \n    .withColumn(\n    "CreatedTS", \n    current_timestamp()  # Records the exact timestamp when this row entered the Silver layer\n) \n    .withColumn(\n    "ModifiedTS", \n    current_timestamp()  # Timestamp of the last modification (initially same as CreatedTS)\n)\n\n# Clean 'CustomerName' column - handle missing or empty values\n# Missing customer names can break downstream analytics or reporting\n# Action: Replace null or empty strings with "Unknown" placeholder\ndf = df.withColumn(\n    "CustomerName",\n    when(\n        # Check if CustomerName is null OR empty string\n        (col("CustomerName").isNull()) | (col("CustomerName") == ""),\n        lit("Unknown")  # Replace with literal string "Unknown"\n    ).otherwise(\n        col("CustomerName")  # Keep original value if it's not null or empty\n    )\n)\n\ndisplay(df)\n#======================================================================================================================\n#======================================================================================================================\n\n#3. Target Delta Table Creation\n#Before loading, we ensure the physical Delta table exists in the metastore with the correct schema.\n#This step is idempotent: if the table exists, nothing happens; if not, it gets created.\n\nfrom pyspark.sql.types import *\nfrom delta.tables import *\n\n# Create the 'sales_silver' Delta table if it doesn't already exist\n# Table Location: sales.dbo.sales_silver (Database: sales, Schema: dbo, Table: sales_silver)\n# Delta Lake ensures ACID transactions, time travel, and schema enforcement\nDeltaTable.createIfNotExists(spark) \n    .tableName("sales.dbo.sales_silver") \n    .addColumn("SalesOrderNumber", StringType()) \n    .addColumn("SalesOrderLineNumber", IntegerType()) \n    .addColumn("OrderDate", DateType()) \n    .addColumn("CustomerName", StringType()) \n    .addColumn("Email", StringType()) \n    .addColumn("Item", StringType()) \n    .addColumn("Quantity", IntegerType()) \n    .addColumn("UnitPrice", FloatType()) \n    .addColumn("Tax", FloatType()) \n    .addColumn("FileName", StringType()) \n    .addColumn("IsFlagged", BooleanType()) \n    .addColumn("CreatedTS", DateType())    # Timestamp of row creation in Silver layer\n    .addColumn("ModifiedTS", DateType())   # Timestamp of last modification\n    .execute()\n\n\n#4. Incremental Loading (Merge / Upsert)\n#This is the most critical part: synchronizing the cleaned DataFrame (updates) with the physical table (silver)  \n#using a Merge operation to prevent duplicates and maintain data consistency.\n#\n#Merge Logic Flow:\n#  1. Compare incoming records (updates) with existing records (silver) using join keys\n#  2. If matching record exists: Execute MATCHED action (currently no-op)\n#  3. If no matching record: Execute NOT MATCHED action (INSERT new record)\n\nfrom delta.tables import *\n\n# Load the existing Delta table from its OneLake storage path\n# OneLake is Microsoft Fabric's unified data repository (similar to ADLS Gen2)\n# Path breakdown: abfss://dp700lab6@onelake.dfs.fabric.microsoft.com/sales.Lakehouse/Tables/dbo/sales_silver\n#   - abfss://: Azure Blob File System Secure protocol\n#   - dp700lab6: Storage account name\n#   - /sales.Lakehouse/Tables/dbo/sales_silver: Logical path within Fabric\ndeltaTable = DeltaTable.forPath(spark, "abfss://dp700lab6@onelake.dfs.fabric.microsoft.com/sales.Lakehouse/Tables/dbo/sales_silver")\n\n# Execute MERGE logic - the core upsert operation for incremental loads\n# This ensures idempotent data loads: re-running the pipeline won't create duplicates\ndeltaTable.alias("silver") \n    .merge(\n        df.alias("updates"),\n        # Join Condition: Identifies unique records using 4 business keys\n        # These 4 columns together uniquely identify a sales line item\n        # If all 4 match, the record already exists in Silver\n        """\n        silver.SalesOrderNumber = updates.SalesOrderNumber AND\n        silver.OrderDate = updates.OrderDate AND\n        silver.CustomerName = updates.CustomerName AND\n        silver.Item = updates.Item\n        """\n    ) \n    .whenMatchedUpdate(set={\n        # ACTION WHEN RECORD EXISTS: Currently empty (no-op)\n        # Potential use cases:\n        #   - Update UnitPrice if source data changed\n        #   - Update Quantity if there are backlog adjustments\n        #   - Update ModifiedTS to track when record was last seen\n        # Example: "UnitPrice": col("updates.UnitPrice")\n    }) \n    .whenNotMatchedInsert(values={\n        # ACTION WHEN NEW RECORD: Insert all columns from the cleaned DataFrame\n        # These are new sales transactions not yet in the Silver layer\n        "SalesOrderNumber": col("updates.SalesOrderNumber"),\n        "SalesOrderLineNumber": col("updates.SalesOrderLineNumber"),\n        "OrderDate": col("updates.OrderDate"),\n        "CustomerName": col("updates.CustomerName"),\n        "Email": col("updates.Email"),\n        "Item": col("updates.Item"),\n        "Quantity": col("updates.Quantity"),\n        "UnitPrice": col("updates.UnitPrice"),\n        "Tax": col("updates.Tax"),\n        "FileName": col("updates.FileName"),                # Data lineage tracking\n        "IsFlagged": col("updates.IsFlagged"),              # Business rule flag\n        "CreatedTS": col("updates.CreatedTS"),              # Audit timestamp\n        "ModifiedTS": col("updates.ModifiedTS")             # Audit timestamp\n    }) \n    .execute()\n